challenge.solution:
class MockFile:
    def close(self): print('closed')

def read_file(filename):
    f = None
    try:
        if filename == 'bad': raise FileNotFoundError()
        f = MockFile()
        content = 'data'
    except FileNotFoundError:
        return None
    else:
        return content
    finally:
        if f: f.close()

print(read_file('good'))

